<?php

use App\Models\FinancialHandover;
use App\Models\DailyCashLedger;
use App\Models\WaiterDailyReconciliation;
use Illuminate\Support\Facades\DB;

DB::beginTransaction();
try {
    // 1. Move the handovers generated by shortage settlement today
    $handovers = FinancialHandover::whereDate('handover_date', '2026-04-20')
        ->where('notes', 'LIKE', '%Generated by shortage settlement%')
        ->get();

    foreach ($handovers as $h) {
        $h->update(['handover_date' => '2026-04-19']);
        echo "Moved Handover #{$h->id} to 2026-04-19\n";
    }

    // 2. Clear the Ledger for April 20 (so it resets to NO ACTIVITY)
    $ledger20 = DailyCashLedger::where('ledger_date', '2026-04-20')->first();
    if ($ledger20) {
        $ledger20->update([
            'total_cash_received' => 0,
            'total_digital_received' => 0,
            'expected_closing_cash' => $ledger20->opening_cash // Reset to opening
        ]);
        $ledger20->syncTotals()->save();
        echo "Reset Ledger for 2026-04-20\n";
    }

    // 3. Update the Ledger for April 19
    $ledger19 = DailyCashLedger::where('ledger_date', '2026-04-19')->first();
    if ($ledger19) {
        $ledger19->syncTotals()->save();
        echo "Synchronized Ledger for 2026-04-19\n";
    }

    // 4. Update the settlement dates inside JSON in WaiterDailyReconciliation
    $recs = WaiterDailyReconciliation::where('notes', 'LIKE', '%2026-04-20%')->get();
    foreach ($recs as $r) {
        $notes = json_decode($r->notes, true);
        if (isset($notes['settlements'])) {
            foreach ($notes['settlements'] as &$s) {
                if (isset($s['date']) && strpos($s['date'], '2026-04-20') !== false) {
                    $s['date'] = str_replace('2026-04-20', '2026-04-19', $s['date']);
                }
            }
            $r->notes = json_encode($notes);
            $r->save();
            echo "Updated settlement record for Staff ID: {$r->waiter_id}\n";
        }
    }

    DB::commit();
    echo "REPAIR SUCCESSFUL: 7,000/- moved to April 19.\n";
} catch (\Exception $e) {
    DB::rollBack();
    echo "REPAIR FAILED: " . $e->getMessage() . "\n";
}
